13	 * Persistent `git cat-file --batch` worker per repo.
14	 *
15	 * Spawning `git show` per request costs ~30-100 ms in process startup and
16	 * a fresh repository scan. With 50+ prefetches per checkpoint this dominates.
17	 * `cat-file --batch` is git's intended fast path: one process, stdin lines
18	 * like `<rev>:<path>\n`, stdout chunks of `<sha> blob <size>\n<bytes>\n`.
19	 */
20	class GitCatFileBatch {
21	  private static workers = new Map<string, GitCatFileBatch>();
22	  static for(repoDir: string): GitCatFileBatch {
23	    let w = GitCatFileBatch.workers.get(repoDir);
24	    if (!w) { w = new GitCatFileBatch(repoDir); GitCatFileBatch.workers.set(repoDir, w); }
