34	  private ensureProc(): ChildProcessWithoutNullStreams {
35	    if (this.proc && !this.proc.killed && this.proc.exitCode == null) return this.proc;
36	    const p = spawnChild("git", ["-C", this.repoDir, "cat-file", "--batch"], { stdio: ["pipe", "pipe", "pipe"] });
37	    this.proc = p;
38	    this.buf = Buffer.alloc(0);
39	    p.stdout.on("data", (d: Buffer) => { this.buf = Buffer.concat([this.buf, d]); this.drain(); });
40	    p.on("exit", () => { this.proc = null; while (this.queue.length) this.queue.shift()!.reject(new Error("cat-file exited")); });
41	    p.on("error", () => { this.proc = null; });
42	    return p;
43	  }
44	
45	  private drain(): void {
46	    while (this.queue.length > 0) {
47	      const nl = this.buf.indexOf(0x0a);
48	      if (nl === -1) return;
49	      const header = this.buf.slice(0, nl).toString("utf8");
50	      const missing = / missing$/.test(header);
51	      if (missing) {
52	        this.buf = this.buf.slice(nl + 1);
53	        this.queue.shift()!.resolve("");
54	        continue;
55	      }
56	      const m = header.match(/^[0-9a-f]+ \w+ (\d+)$/);
57	      if (!m) {
58	        // Unparseable — bail, kill the process so subsequent calls re-spawn.
59	        const err = new Error(`cat-file: unexpected header ${JSON.stringify(header)}`);
60	        while (this.queue.length) this.queue.shift()!.reject(err);
61	        try { this.proc?.kill(); } catch { /* noop */ }
62	        this.proc = null;
63	        return;
64	      }
65	      const size = parseInt(m[1], 10);
66	      const start = nl + 1;
67	      const end = start + size;
68	      if (this.buf.length < end + 1) return; // wait for the rest + trailing \n
69	      const body = this.buf.slice(start, end).toString("utf8");
70	      this.buf = this.buf.slice(end + 1);
71	      this.queue.shift()!.resolve(body);
72	    }
73	  }
