149	async function pushSchema(db: PrismaClient): Promise<void> {
150	  const sql = readFileSync(SCHEMA_SQL_PATH, "utf8");
151	  // Split on statement boundaries (semicolon + newline) and execute each one.
152	  // Strip leading SQL comment lines (e.g. "-- CreateTable") from each chunk
153	  // so that they don't prevent execution.
154	  const stmts = sql
155	    .split(/;\s*\n/)
156	    .map((s) => s.replace(/^(\s*--.*\n)*/gm, "").trim())
157	    .filter((s) => s.length > 0);
158	  for (const stmt of stmts) {
159	    await db.$executeRawUnsafe(stmt);
160	  }
161	
162	  // Ad-hoc ADD COLUMN migrations for DBs created before a column was added.
163	  // SQLite has no IF NOT EXISTS for ADD COLUMN, so we swallow "duplicate column".
164	  for (const { table, col, type } of [
165	    { table: "ShadowSession", col: "gitUserName",  type: "TEXT" },
166	    { table: "ShadowSession", col: "gitUserEmail", type: "TEXT" },
167	    { table: "LogEvent",      col: "gitUserName",  type: "TEXT" },
168	    { table: "LogEvent",      col: "gitUserEmail", type: "TEXT" },
169	  ]) {
170	    try {
171	      await db.$executeRawUnsafe(`ALTER TABLE "${table}" ADD COLUMN "${col}" ${type}`);
172	    } catch (err) {
173	      if (!/duplicate column/i.test(String(err))) throw err;
174	    }
175	  }
176	
177	  // Backfill LogEvent.gitUserName/Email from the checkpoint that produced it.
178	  // Every LogEvent row with a sessionLinkId came from a CheckpointMetadata
179	  // transcript, and the commit that created that checkpoint is its author.
180	  // Runs once per server start; subsequent rows are populated at insert time.
181	  // We probe first because the UPDATE walks the join even when nothing changes
182	  // — a 6 s+ stall on big DBs in the hot path of every cold connection.
183	  const probe = await db.$queryRawUnsafe<{ n: number }[]>(
184	    `SELECT 1 AS n FROM LogEvent
185	       WHERE sessionLinkId IS NOT NULL
186	         AND (gitUserName IS NULL OR gitUserEmail IS NULL)
187	       LIMIT 1`,
188	  );
189	  if (probe.length > 0) {
190	    await db.$executeRawUnsafe(`
191	      UPDATE LogEvent
192	      SET gitUserName = (
193	        SELECT cm.gitUserName FROM SessionLink sl
194	        JOIN CheckpointMetadata cm ON sl.checkpointMetadataId = cm.id
195	        WHERE sl.id = LogEvent.sessionLinkId
196	      )
197	      WHERE LogEvent.gitUserName IS NULL
198	        AND LogEvent.sessionLinkId IS NOT NULL
199	    `);
200	    await db.$executeRawUnsafe(`
201	      UPDATE LogEvent
202	      SET gitUserEmail = (
203	        SELECT cm.gitUserEmail FROM SessionLink sl
204	        JOIN CheckpointMetadata cm ON sl.checkpointMetadataId = cm.id
205	        WHERE sl.id = LogEvent.sessionLinkId
206	      )
207	      WHERE LogEvent.gitUserEmail IS NULL
208	        AND LogEvent.sessionLinkId IS NOT NULL
209	    `);
210	  }
211	}
