226	// detail latency when nothing's cached. Config changes are rare; a 60 s TTL
227	// is safe and re-reads on demand are still possible after expiry.
228	const gitUserCache = new Map<string, { value: { name: string | null; email: string | null }; expires: number }>();
229	const GIT_USER_TTL_MS = 60_000;
230	
231	function getGitUser(cwd?: string): { name: string | null; email: string | null } {
232	  const key = cwd ?? "<global>";
233	  const now = Date.now();
234	  const hit = gitUserCache.get(key);
235	  if (hit && hit.expires > now) return hit.value;
236	
237	  // Try local config first (cwd), then fall back to global
238	  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
239	  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
240	  const value = { name, email };
241	  gitUserCache.set(key, { value, expires: now + GIT_USER_TTL_MS });
