282	  customTitle: string | null;
283	  agent: string | null;
284	  /** true when this session is currently indexed in a shadow branch */
285	  isLive: boolean;
286	}
287	
288	interface OverviewResponse {
289	  sessionId: string;
290	  summary: string;
291	  keywords: string[];
292	  startedAt: string;
293	  endedAt: string;
294	}
295	
296	// ─── Mapping helpers ──────────────────────────────────────────────────────────
297	
298	// SQLite has a limit of 999 bind variables per statement. When doing IN queries
299	// over large sets, chunk and union the results.
