// ─── Custom title cache (reads ~/.claude/projects/…/*.jsonl for /rename events) ──

/** Map from sessionId → the latest customTitle set via /rename. */
const customTitleCache = new Map<string, string>();
/** Track file mtimes so we only re-parse files that have changed. */
const customTitleMtimes = new Map<string, number>();

function refreshCustomTitles(repoDir: string): void {
  // Claude encodes the repo path by replacing every '/' with '-'
  const encoded = repoDir.replace(/\//g, "-");
  const projectDir = join(homedir(), ".claude", "projects", encoded);
  let files: string[];
  try {
    files = readdirSync(projectDir).filter((f) => f.endsWith(".jsonl"));
  } catch {
    return; // project dir doesn't exist for this repo yet
  }

  for (const file of files) {
    const filePath = join(projectDir, file);
    let mtime: number;
    try { mtime = statSync(filePath).mtimeMs; } catch { continue; }
    if (customTitleMtimes.get(filePath) === mtime) continue; // unchanged
    customTitleMtimes.set(filePath, mtime);

    const sessionId = file.slice(0, -".jsonl".length);
    let latestTitle: string | null = null;
    try {
      for (const line of readFileSync(filePath, "utf-8").split("\n")) {
        const trimmed = line.trim();
        if (!trimmed) continue;
        try {
          const obj = JSON.parse(trimmed) as Record<string, unknown>;
          if (obj.type === "custom-title" && typeof obj.customTitle === "string") {
            latestTitle = obj.customTitle;
          }
        } catch { /* skip malformed line */ }
      }
    } catch { /* file unreadable */ }

    if (latestTitle) customTitleCache.set(sessionId, latestTitle);
    else customTitleCache.delete(sessionId);
  }
}

// ─── Schema initialisation ────────────────────────────────────────────────────

const SCRIPT_DIR = dirname(fileURLToPath(import.meta.url));

// schema.sql is generated at build time by `prisma migrate diff --from-empty --to-schema ...`
// and transformed to use CREATE TABLE IF NOT EXISTS / CREATE INDEX IF NOT EXISTS.
// In dev: dist/schema.sql (copied by tsconfig); bundled VSIX: bundled-server/schema.sql.
const SCHEMA_SQL_DEV     = join(SCRIPT_DIR, "schema.sql");
const SCHEMA_SQL_BUNDLED = join(SCRIPT_DIR, "schema.sql"); // same name, different dir
const SCHEMA_SQL_PATH    = existsSync(SCHEMA_SQL_DEV) ? SCHEMA_SQL_DEV : SCHEMA_SQL_BUNDLED;

async function pushSchema(db: PrismaClient): Promise<void> {
  const sql = readFileSync(SCHEMA_SQL_PATH, "utf8");
  // Split on statement boundaries (semicolon + newline) and execute each one.
  // Strip leading SQL comment lines (e.g. "-- CreateTable") from each chunk
  // so that they don't prevent execution.
  const stmts = sql
    .split(/;\s*\n/)
    .map((s) => s.replace(/^(\s*--.*\n)*/gm, "").trim())
    .filter((s) => s.length > 0);
  for (const stmt of stmts) {
    await db.$executeRawUnsafe(stmt);
  }

  // Ad-hoc ADD COLUMN migrations for DBs created before a column was added.
  // SQLite has no IF NOT EXISTS for ADD COLUMN, so we swallow "duplicate column".
  for (const { table, col, type } of [
    { table: "ShadowSession", col: "gitUserName",  type: "TEXT" },
    { table: "ShadowSession", col: "gitUserEmail", type: "TEXT" },
    { table: "LogEvent",      col: "gitUserName",  type: "TEXT" },
    { table: "LogEvent",      col: "gitUserEmail", type: "TEXT" },
  ]) {
    try {
      await db.$executeRawUnsafe(`ALTER TABLE "${table}" ADD COLUMN "${col}" ${type}`);
    } catch (err) {
      if (!/duplicate column/i.test(String(err))) throw err;
    }
  }

  // Backfill LogEvent.gitUserName/Email from the checkpoint that produced it.
  // Every LogEvent row with a sessionLinkId came from a CheckpointMetadata
  // transcript, and the commit that created that checkpoint is its author.
  // Runs once per server start; subsequent rows are populated at insert time.
  // We probe first because the UPDATE walks the join even when nothing changes
  // — a 6 s+ stall on big DBs in the hot path of every cold connection.
  const probe = await db.$queryRawUnsafe<{ n: number }[]>(
    `SELECT 1 AS n FROM LogEvent
       WHERE sessionLinkId IS NOT NULL
         AND (gitUserName IS NULL OR gitUserEmail IS NULL)
       LIMIT 1`,
  );
  if (probe.length > 0) {
    await db.$executeRawUnsafe(`
      UPDATE LogEvent
      SET gitUserName = (
        SELECT cm.gitUserName FROM SessionLink sl
        JOIN CheckpointMetadata cm ON sl.checkpointMetadataId = cm.id
        WHERE sl.id = LogEvent.sessionLinkId
      )
      WHERE LogEvent.gitUserName IS NULL
        AND LogEvent.sessionLinkId IS NOT NULL
    `);
    await db.$executeRawUnsafe(`
      UPDATE LogEvent
      SET gitUserEmail = (
        SELECT cm.gitUserEmail FROM SessionLink sl
        JOIN CheckpointMetadata cm ON sl.checkpointMetadataId = cm.id
        WHERE sl.id = LogEvent.sessionLinkId
      )
      WHERE LogEvent.gitUserEmail IS NULL
        AND LogEvent.sessionLinkId IS NOT NULL
    `);
  }
}

// ─── Git user ─────────────────────────────────────────────────────────────────

function gitConfigGet(key: string, cwd?: string): string | null {
  try {
    return execSync(`git config ${key}`, {
      cwd,
      encoding: "utf8",
      stdio: ["ignore", "pipe", "ignore"],
    }).trim() || null;
  } catch { return null; }
}

// Cache git config lookups — they shell out per call and dominate session
// detail latency when nothing's cached. Config changes are rare; a 60 s TTL
// is safe and re-reads on demand are still possible after expiry.
const gitUserCache = new Map<string, { value: { name: string | null; email: string | null }; expires: number }>();
const GIT_USER_TTL_MS = 60_000;

function getGitUser(cwd?: string): { name: string | null; email: string | null } {
  const key = cwd ?? "<global>";
  const now = Date.now();
  const hit = gitUserCache.get(key);
  if (hit && hit.expires > now) return hit.value;

  // Try local config first (cwd), then fall back to global
  const name  = (cwd ? gitConfigGet("user.name", cwd)  : null) ?? gitConfigGet("--global user.name");
  const email = (cwd ? gitConfigGet("user.email", cwd) : null) ?? gitConfigGet("--global user.email");
  const value = { name, email };
  gitUserCache.set(key, { value, expires: now + GIT_USER_TTL_MS });
  return value;
}

/**
 * Returns true when the session's git user (name or email) matches the git user
 * configured on this machine for the given cwd.
 */
function isSessionLocalUser(
  sessionName: string | null,
  sessionEmail: string | null,
  cwd: string,
): boolean {
  const local = getGitUser(cwd);
  if (local.email && sessionEmail && local.email === sessionEmail) return true;
  if (local.name  && sessionName  && local.name  === sessionName)  return true;
  return false;
}

// ─── Response types ───────────────────────────────────────────────────────────

interface SessionResponse {
  sessionId: string;
  startedAt: string;
  updatedAt: string;
  cwd: string;
  cwdExists: boolean;
  /** true when cwd exists locally AND the session's git user matches this machine's git user */
  isLocalSession: boolean;
  repoRoot: string | null;
  repoName: string | null;
  parentSessionId: string | null;
