175	    },
176	  });
177	  return row.id;
178	}
179	
180	// ─── V2 single-checkpoint indexer ────────────────────────────────────────────
181	
182	/**
183	 * Index one checkpoint directory using the new normalized schema.
184	 *
185	 * Reads:
186	 *   <checkpointDir>/metadata.json             → CheckpointMetadata
187	 *   <checkpointDir>/<n>/metadata.json         → CheckpointSessionMetadata
188	 *   <checkpointDir>/<n>/content_hash.txt      → SessionLink.contentHash (actual hash)
189	 *   <checkpointDir>/<n>/{full.jsonl,context.md,prompt.txt} → SessionLink paths
190	 */
191	export async function indexCheckpointV2(
192	  db: PrismaClient,
193	  checkpointDir: string,
194	  checkpointId: string,
195	  repoPath?: string,
196	  mappedCheckpointIds?: Set<string>,
197	): Promise<void> {
198	  const metaPath = join(checkpointDir, "metadata.json");
199	  if (!existsSync(metaPath)) throw new Error(`No metadata.json at ${checkpointDir}`);
200	
201	  const meta = JSON.parse(readFileSync(metaPath, "utf8")) as RootMeta;
202	
203	  // Upsert CheckpointMetadata — create TokenUsage only on first insert
204	  const existingMeta = await db.checkpointMetadata.findUnique({
205	    where: { checkpointId },
206	    select: { id: true, gitUserName: true, gitUserEmail: true },
207	  });
208	
209	  // Look up the true author of this checkpoint from the checkpoint-branch commit.
210	  // This is independent of the main-branch git history (which may not be reachable
211	  // for checkpoints made by other users), so it works correctly across machines.
212	  // Only look up if we don't already have an author on record — git log --grep is slow.
213	  const needsAuthorLookup = !existingMeta?.gitUserName && !existingMeta?.gitUserEmail;
214	  const author = needsAuthorLookup ? await findCheckpointAuthor(checkpointDir, checkpointId) : null;
215	
216	  let checkpointMeta: { id: number };
217	  if (!existingMeta) {
218	    let tokenUsageId: number | null = null;
219	    if (meta.token_usage) tokenUsageId = await createTokenUsage(db, meta.token_usage);
220	    checkpointMeta = await db.checkpointMetadata.create({
221	      data: {
222	        checkpointId,
223	        cliVersion:       meta.cli_version       ?? null,
224	        branch:           meta.branch            ?? null,
225	        strategy:         meta.strategy          ?? null,
226	        checkpointsCount: meta.checkpoints_count ?? 0,
227	        gitUserName:      author?.name  || null,
228	        gitUserEmail:     author?.email || null,
229	        tokenUsageId,
230	      },
231	      select: { id: true },
232	    });
233	  } else {
234	    await db.checkpointMetadata.update({
235	      where: { checkpointId },
236	      data: {
237	        cliVersion:       meta.cli_version       ?? null,
238	        branch:           meta.branch            ?? null,
239	        strategy:         meta.strategy          ?? null,
240	        checkpointsCount: meta.checkpoints_count ?? 0,
241	        ...(author ? { gitUserName: author.name || null, gitUserEmail: author.email || null } : {}),
242	      },
243	    });
244	    checkpointMeta = { id: existingMeta.id };
245	  }
246	
247	  // files_touched → FilePath + join table
248	  for (const filePath of meta.files_touched ?? []) {
249	    const filePathId = await upsertFilePath(db, filePath);
250	    await db.checkpointMetadataFilePath.upsert({
251	      where: { checkpointMetadataId_filePathId: { checkpointMetadataId: checkpointMeta.id, filePathId } },
252	      create: { checkpointMetadataId: checkpointMeta.id, filePathId },
253	      update: {},
254	    });
255	  }
256	
257	  // Session sub-directories: 0/, 1/, …
258	  const sessionDirs = readdirSync(checkpointDir)
259	    .filter((e) => /^\d+$/.test(e) && statSync(join(checkpointDir, e)).isDirectory())
260	    .sort((a, b) => parseInt(a) - parseInt(b));
261	
262	  for (const sessionDir of sessionDirs) {
263	    const sessionPath    = join(checkpointDir, sessionDir);
264	    const metadataFile   = join(sessionPath, "metadata.json");
265	    const transcriptFile = join(sessionPath, "full.jsonl");
266	    const contextFile    = join(sessionPath, "context.md");
267	    const hashFile       = join(sessionPath, "content_hash.txt");
268	    const promptFile     = join(sessionPath, "prompt.txt");
269	
270	    // Read actual hash content (not the file path)
271	    const contentHash = existsSync(hashFile) ? readFileSync(hashFile, "utf8").trim() : null;
272	
273	    // Look up an existing SessionLink for this transcript path.
274	    const transcriptVal = existsSync(transcriptFile) ? transcriptFile : null;
275	    const existing = transcriptVal
276	      ? await db.sessionLink.findFirst({
277	          where: { checkpointMetadataId: checkpointMeta.id, transcript: transcriptVal },
278	          select: { id: true, contentHash: true },
279	        })
280	      : null;
281	
282	    // If the content hash hasn't changed, this session is fully indexed — skip it.
283	    if (existing && contentHash && existing.contentHash === contentHash) continue;
284	
285	    let sessionLink: { id: number };
286	    if (existing) {
287	      // Hash changed (JSONL grew) — update the stored hash and re-index.
288	      sessionLink = await db.sessionLink.update({
289	        where: { id: existing.id },
290	        data: { contentHash },
291	        select: { id: true },
292	      });
293	    } else {
294	      sessionLink = await db.sessionLink.create({
295	        data: {
296	          checkpointMetadataId: checkpointMeta.id,
297	          metadata:   existsSync(metadataFile)   ? metadataFile   : null,
298	          transcript: transcriptVal,
299	          context:    existsSync(contextFile)    ? contextFile    : null,
