723	export async function indexAllCheckpointsV2(
724	  db: PrismaClient,
725	  rootDir: string,
726	  onProgress?: (checkpointId: string) => void,
727	  repoPath?: string,
728	): Promise<{ checkpoints: number }> {
729	  let totalCheckpoints = 0;
730	
731	  // Pre-fetch all checkpoint IDs that already have a git OID mapping so we
732	  // can skip the per-checkpoint DB read inside saveGitOidMapping.
733	  let mappedCheckpointIds: Set<string> | undefined;
734	  if (repoPath) {
735	    const rows = await db.checkpointIdGitOidJoin.findMany({ select: { checkpointId: true } });
736	    mappedCheckpointIds = new Set(rows.map((r) => r.checkpointId));
737	  }
738	
739	  const shards = readdirSync(rootDir)
740	    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
741	
742	  for (const shard of shards) {
743	    const shardPath = join(rootDir, shard);
744	    const ids = readdirSync(shardPath)
745	      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
746	
747	    for (const rest of ids) {
748	      const checkpointId  = shard + rest;
749	      const checkpointDir = join(shardPath, rest);
750	      try {
751	        await indexCheckpointV2(db, checkpointDir, checkpointId, repoPath, mappedCheckpointIds);
752	        mappedCheckpointIds?.add(checkpointId); // keep set current for this pass
753	        totalCheckpoints++;
754	        onProgress?.(checkpointId);
755	      } catch (err) {
756	        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
757	      }
758	    }
759	  }
760	
761	  // Sync FTS index with any new LogContent rows added during this pass
762	  await setupLogContentFts(db);
763	  await syncLogContentFts(db);
764	
765	  return { checkpoints: totalCheckpoints };
766	}
