788	// ─── Shadow branch indexer ────────────────────────────────────────────────────
789	//
790	// Shadow branches (entire/<commit>-<hash>) hold in-progress sessions that
791	// haven't been committed to entire/checkpoints/v1 yet. Each branch contains:
792	//
793	//   .entire/metadata/<session-id>/full.jsonl   — live transcript
794	//   .entire/metadata/<session-id>/prompt.txt   — initial user prompt
795	//
796	// We read these directly from git (git ls-tree + git cat-file blob) so we
797	// don't need a worktree checkout. Change detection is via the git blob SHA.
798	
799	function gitExec(args: string, cwd: string): string {
800	  return execSync(`git ${args}`, {
801	    cwd,
802	    encoding: "utf8",
803	    stdio: ["ignore", "pipe", "ignore"],
804	    maxBuffer: 64 * 1024 * 1024,
805	  });
806	}
807	
808	function getShadowBranches(repoPath: string): string[] {
809	  try {
810	    return gitExec("branch", repoPath)
811	      .split("\n")
812	      .map((l) => l.trim().replace(/^\* /, ""))
813	      .filter((b) => b.startsWith("entire/") && !b.startsWith("entire/checkpoints"));
814	  } catch { return []; }
815	}
816	
817	function getShadowSessions(repoPath: string, branch: string): { sessionId: string; blobSha: string }[] {
818	  try {
819	    const output = gitExec(`ls-tree -r ${branch} -- .entire/metadata/`, repoPath);
820	    const sessions = new Map<string, string>();
821	    for (const line of output.split("\n")) {
822	      const m = line.match(/^100644 blob ([0-9a-f]+)\s+\.entire\/metadata\/([^/]+)\/full\.jsonl$/);
823	      if (m) sessions.set(m[2], m[1]);
824	    }
825	    return [...sessions.entries()].map(([sessionId, blobSha]) => ({ sessionId, blobSha }));
826	  } catch { return []; }
827	}
828	
829	function readBlobContent(repoPath: string, blobSha: string): string {
830	  return gitExec(`cat-file blob ${blobSha}`, repoPath);
831	}
