833	/** Author of the shadow branch tip — the user who ran Entire for that session. */
834	function getShadowBranchAuthor(repoPath: string, branch: string): { name: string | null; email: string | null } {
835	  try {
836	    const out = gitExec(`log -1 --format=%an%n%ae ${branch}`, repoPath).split("\n");
837	    return { name: out[0]?.trim() || null, email: out[1]?.trim() || null };
838	  } catch { return { name: null, email: null }; }
