841	/**
842	 * Per-line authorship for a session's full.jsonl at a given revision (branch
843	 * name or commit SHA). Returns a map keyed by each event's `uuid` (or
844	 * `messageId` if uuid is absent) to the author of the shadow-branch commit
845	 * that introduced that line.
846	 *
847	 * Entire rewrites the full file each turn, but git blame correctly carries
848	 * unchanged lines forward to their original commit.
849	 */
850	function getJsonlLineAuthors(
851	  repoPath: string,
852	  rev: string,
853	  sessionId: string,
854	): Map<string, { name: string | null; email: string | null }> {
855	  const map = new Map<string, { name: string | null; email: string | null }>();
856	  const jsonPath = `.entire/metadata/${sessionId}/full.jsonl`;
857	  let porcelain: string;
858	  try {
859	    porcelain = gitExec(`blame --line-porcelain ${rev} -- ${JSON.stringify(jsonPath)}`, repoPath);
860	  } catch { return map; }
861	
862	  // Porcelain format per line:
863	  //   <sha> <orig-lineno> <final-lineno> [<group-size>]
864	  //   author <name>
865	  //   author-mail <<email>>
866	  //   ...
867	  //   \t<file contents>
868	  let curName: string | null = null;
869	  let curEmail: string | null = null;
870	  for (const line of porcelain.split("\n")) {
871	    if (line.startsWith("author ")) { curName = line.slice("author ".length).trim() || null; }
872	    else if (line.startsWith("author-mail ")) {
873	      const m = line.slice("author-mail ".length).trim().match(/^<(.*)>$/);
874	      curEmail = m ? m[1] || null : null;
875	    } else if (line.startsWith("\t")) {
876	      // Actual file content for this blame record.
877	      const content = line.slice(1).trim();
878	      if (!content) continue;
879	      try {
880	        const obj = JSON.parse(content) as { uuid?: string; messageId?: string };
881	        const key = obj.uuid ?? obj.messageId;
882	        if (key && !map.has(key)) map.set(key, { name: curName, email: curEmail });
883	      } catch { /* skip non-JSON or malformed */ }
884	    }
885	  }
886	  return map;
887	}
