892	 * pruned — the commits still exist (reachable via other refs) even though
893	 * the branch name is gone.
894	 */
895	function findAnyCommitForSessionJsonl(repoPath: string, sessionId: string): string | null {
896	  const jsonPath = `.entire/metadata/${sessionId}/full.jsonl`;
897	  try {
898	    const out = gitExec(`log --all -1 --format=%H -- ${JSON.stringify(jsonPath)}`, repoPath).trim();
899	    return out || null;
900	  } catch { return null; }
901	}
