// ─── V2 full-tree indexer ─────────────────────────────────────────────────────

export async function indexAllCheckpointsV2(
  db: PrismaClient,
  rootDir: string,
  onProgress?: (checkpointId: string) => void,
  repoPath?: string,
): Promise<{ checkpoints: number }> {
  let totalCheckpoints = 0;

  // Pre-fetch all checkpoint IDs that already have a git OID mapping so we
  // can skip the per-checkpoint DB read inside saveGitOidMapping.
  let mappedCheckpointIds: Set<string> | undefined;
  if (repoPath) {
    const rows = await db.checkpointIdGitOidJoin.findMany({ select: { checkpointId: true } });
    mappedCheckpointIds = new Set(rows.map((r) => r.checkpointId));
  }

  const shards = readdirSync(rootDir)
    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());

  for (const shard of shards) {
    const shardPath = join(rootDir, shard);
    const ids = readdirSync(shardPath)
      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());

    for (const rest of ids) {
      const checkpointId  = shard + rest;
      const checkpointDir = join(shardPath, rest);
      try {
        await indexCheckpointV2(db, checkpointDir, checkpointId, repoPath, mappedCheckpointIds);
        mappedCheckpointIds?.add(checkpointId); // keep set current for this pass
        totalCheckpoints++;
        onProgress?.(checkpointId);
      } catch (err) {
        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
      }
    }
  }

  // Sync FTS index with any new LogContent rows added during this pass
  await setupLogContentFts(db);
  await syncLogContentFts(db);

  return { checkpoints: totalCheckpoints };
}

// ─── Full-tree indexer ───────────────────────────────────────────────────────

/**
 * Walk a checkpoints root directory and index every checkpoint found.
 *
 * The root must have the shard structure:
 *   <root>/<2-hex-chars>/<10-hex-chars>/
 *
 * @param onProgress  Optional callback called after each checkpoint.
 */
export async function indexAllCheckpoints(
  db: PrismaClient,
  rootDir: string,
  onProgress?: (checkpointId: string) => void,
  repoPath?: string,
): Promise<{ checkpoints: number }> {
  const result = await indexAllCheckpointsV2(db, rootDir, onProgress, repoPath);
  return { checkpoints: result.checkpoints };
}

// ─── Shadow branch indexer ────────────────────────────────────────────────────
//
// Shadow branches (entire/<commit>-<hash>) hold in-progress sessions that
// haven't been committed to entire/checkpoints/v1 yet. Each branch contains:
//
//   .entire/metadata/<session-id>/full.jsonl   — live transcript
//   .entire/metadata/<session-id>/prompt.txt   — initial user prompt
//
// We read these directly from git (git ls-tree + git cat-file blob) so we
// don't need a worktree checkout. Change detection is via the git blob SHA.

function gitExec(args: string, cwd: string): string {
  return execSync(`git ${args}`, {
    cwd,
    encoding: "utf8",
    stdio: ["ignore", "pipe", "ignore"],
    maxBuffer: 64 * 1024 * 1024,
  });
}

function getShadowBranches(repoPath: string): string[] {
  try {
    return gitExec("branch", repoPath)
      .split("\n")
      .map((l) => l.trim().replace(/^\* /, ""))
      .filter((b) => b.startsWith("entire/") && !b.startsWith("entire/checkpoints"));
  } catch { return []; }
}

function getShadowSessions(repoPath: string, branch: string): { sessionId: string; blobSha: string }[] {
  try {
    const output = gitExec(`ls-tree -r ${branch} -- .entire/metadata/`, repoPath);
    const sessions = new Map<string, string>();
    for (const line of output.split("\n")) {
      const m = line.match(/^100644 blob ([0-9a-f]+)\s+\.entire\/metadata\/([^/]+)\/full\.jsonl$/);
      if (m) sessions.set(m[2], m[1]);
    }
    return [...sessions.entries()].map(([sessionId, blobSha]) => ({ sessionId, blobSha }));
  } catch { return []; }
}

function readBlobContent(repoPath: string, blobSha: string): string {
  return gitExec(`cat-file blob ${blobSha}`, repoPath);
}

/** Author of the shadow branch tip — the user who ran Entire for that session. */
function getShadowBranchAuthor(repoPath: string, branch: string): { name: string | null; email: string | null } {
  try {
    const out = gitExec(`log -1 --format=%an%n%ae ${branch}`, repoPath).split("\n");
    return { name: out[0]?.trim() || null, email: out[1]?.trim() || null };
  } catch { return { name: null, email: null }; }
}

/**
 * Per-line authorship for a session's full.jsonl at a given revision (branch
 * name or commit SHA). Returns a map keyed by each event's `uuid` (or
 * `messageId` if uuid is absent) to the author of the shadow-branch commit
 * that introduced that line.
 *
 * Entire rewrites the full file each turn, but git blame correctly carries
 * unchanged lines forward to their original commit.
 */
function getJsonlLineAuthors(
  repoPath: string,
  rev: string,
  sessionId: string,
): Map<string, { name: string | null; email: string | null }> {
  const map = new Map<string, { name: string | null; email: string | null }>();
  const jsonPath = `.entire/metadata/${sessionId}/full.jsonl`;
  let porcelain: string;
  try {
    porcelain = gitExec(`blame --line-porcelain ${rev} -- ${JSON.stringify(jsonPath)}`, repoPath);
  } catch { return map; }

  // Porcelain format per line:
  //   <sha> <orig-lineno> <final-lineno> [<group-size>]
  //   author <name>
  //   author-mail <<email>>
  //   ...
  //   \t<file contents>
  let curName: string | null = null;
  let curEmail: string | null = null;
  for (const line of porcelain.split("\n")) {
    if (line.startsWith("author ")) { curName = line.slice("author ".length).trim() || null; }
    else if (line.startsWith("author-mail ")) {
      const m = line.slice("author-mail ".length).trim().match(/^<(.*)>$/);
      curEmail = m ? m[1] || null : null;
    } else if (line.startsWith("\t")) {
      // Actual file content for this blame record.
      const content = line.slice(1).trim();
      if (!content) continue;
      try {
        const obj = JSON.parse(content) as { uuid?: string; messageId?: string };
        const key = obj.uuid ?? obj.messageId;
        if (key && !map.has(key)) map.set(key, { name: curName, email: curEmail });
      } catch { /* skip non-JSON or malformed */ }
    }
  }
  return map;
}

/**
 * Locate the most recent commit on any ref that touched this session's
 * full.jsonl. Useful for sessions whose originating shadow branch has been
 * pruned — the commits still exist (reachable via other refs) even though
 * the branch name is gone.
 */
function findAnyCommitForSessionJsonl(repoPath: string, sessionId: string): string | null {
  const jsonPath = `.entire/metadata/${sessionId}/full.jsonl`;
  try {
    const out = gitExec(`log --all -1 --format=%H -- ${JSON.stringify(jsonPath)}`, repoPath).trim();
    return out || null;
  } catch { return null; }
}

function readPromptFromBranch(repoPath: string, branch: string, sessionId: string): string | null {
  try {
    return gitExec(`show ${branch}:.entire/metadata/${sessionId}/prompt.txt`, repoPath).trim();
  } catch { return null; }
}

/**
 * Index all sessions from all local shadow branches (entire/<x>-<y>).
 * Reads transcripts directly from git — no worktree required.
 * Returns the number of sessions that had new or updated content.
 */
export async function indexAllShadowBranches(
  db: PrismaClient,
  repoPath: string,
): Promise<{ sessions: number }> {
  const branches = getShadowBranches(repoPath);
  let totalSessions = 0;

  for (const branch of branches) {
    const sessions = getShadowSessions(repoPath, branch);
    const branchAuthor = getShadowBranchAuthor(repoPath, branch);

    for (const { sessionId, blobSha } of sessions) {
      // Skip if this exact blob SHA has already been indexed for this session.
      // (Same session appears in multiple shadow branches as its transcript grows;
      //  each branch may have a different SHA even for the same underlying content.)
      const existing = await db.shadowSession.findUnique({ where: { sessionId } });
      const seenShas: string[] = existing ? (JSON.parse(existing.seenBlobShas) as string[]) : [];
      if (seenShas.includes(blobSha)) {
        // Backfill: if this row was created before we tracked the author,
        // patch it in without re-indexing the blob.
        if (existing && !existing.gitUserName && !existing.gitUserEmail && (branchAuthor.name || branchAuthor.email)) {
          await db.shadowSession.update({
            where: { sessionId },
            data:  { gitUserName: branchAuthor.name, gitUserEmail: branchAuthor.email },
          });
        }
        // Per-event author backfill: LogEvents with NULL gitUserName need the blame map.
        // Only pay the cost if this session actually has any such rows.
        if (existing) {
          const missing = await db.logEvent.count({ where: { shadowSessionId: existing.id, gitUserName: null } });
          if (missing > 0) {
            const authorByKey = getJsonlLineAuthors(repoPath, branch, sessionId);
            if (authorByKey.size > 0) {
              const rows = await db.logEvent.findMany({
                where: { shadowSessionId: existing.id, gitUserName: null },
                select: { id: true, uuid: true, messageId: true },
              });
              for (const r of rows) {
                const key = r.uuid ?? r.messageId;
                const a = key ? authorByKey.get(key) : undefined;
                if (a && (a.name || a.email)) {
                  await db.logEvent.update({ where: { id: r.id }, data: { gitUserName: a.name ?? null, gitUserEmail: a.email ?? null } });
                }
              }
            }
          }
        }
        continue;
      }

      const fullJsonlContent = readBlobContent(repoPath, blobSha);
      const events = parseFullJsonl(fullJsonlContent);

      // Extract session metadata from the first event that carries each field.
      // Some early events (e.g. permission-mode) have sessionId but no cwd/branch,
      // so we search for each field independently to avoid missing real values.
      const cwdEvent    = events.find((e) => e.cwd);
      const branchEvent = events.find((e) => e.gitBranch);
      const timeEvent   = events.find((e) => e.timestamp);
      const cwd       = cwdEvent?.cwd       ?? null;
      const gitBranch = branchEvent?.gitBranch ?? null;
      const createdAt = timeEvent?.timestamp ? new Date(timeEvent.timestamp) : null;
      const prompt    = readPromptFromBranch(repoPath, branch, sessionId);
      const newSeenShas = JSON.stringify([...seenShas, blobSha]);

      const shadowSession = await db.shadowSession.upsert({
        where:  { sessionId },
        create: { sessionId, branch, seenBlobShas: newSeenShas, prompt, cwd, gitBranch, createdAt, gitUserName: branchAuthor.name, gitUserEmail: branchAuthor.email },
        update: {
          branch, seenBlobShas: newSeenShas, prompt, cwd, gitBranch, createdAt,
          // Only fill user fields if we found a value and the row doesn't already have one.
          ...(branchAuthor.name  && !existing?.gitUserName  ? { gitUserName:  branchAuthor.name  } : {}),
          ...(branchAuthor.email && !existing?.gitUserEmail ? { gitUserEmail: branchAuthor.email } : {}),
        },
      });

      const authorByKey = getJsonlLineAuthors(repoPath, branch, sessionId);
      const { events: newEvents } = await indexFullJsonlContent(db, fullJsonlContent, undefined, shadowSession.id, authorByKey);

      process.stderr.write(`shadow indexer: indexed session ${sessionId.slice(0, 8)} (+${newEvents} events) from ${branch}\n`);
      totalSessions++;
    }

    // Also index task checkpoint files to build parent-child session relationships.
    await indexTaskRelationships(db, repoPath, branch);
  }

  if (totalSessions > 0) {
    await setupLogContentFts(db);
    await syncLogContentFts(db);
  }

  return { sessions: totalSessions };
}

/**
 * Index live session transcripts directly from `.entire/metadata/<sessionId>/full.jsonl`.
 *
 * Entire writes these files while a session is active, before committing them to
 * a shadow branch. Reading them directly lets us show brand-new sessions in the UI
 * within seconds instead of waiting for the shadow-branch commit (which can take
 * minutes, since Entire only commits at checkpoint boundaries).
 *
 * Change detection uses the file's (mtimeMs, size) pair — cheap to check and
 * reliable for append-only transcripts. Stored in the `seenBlobShas` field of
 * ShadowSession as the synthetic tag `live:<mtimeMs>:<size>` so it doesn't collide
 * with real git blob SHAs.
 */
export async function indexLiveSessions(
  db: PrismaClient,
  repoPath: string,
): Promise<{ sessions: number }> {
  const metadataDir = join(repoPath, ".entire", "metadata");
  if (!existsSync(metadataDir)) return { sessions: 0 };

  let totalSessions = 0;
  let sessionDirs: string[];
  try {
    sessionDirs = readdirSync(metadataDir).filter((name) => {
      try { return statSync(join(metadataDir, name)).isDirectory(); }
      catch { return false; }
    });
  } catch { return { sessions: 0 }; }

  for (const sessionId of sessionDirs) {
    const jsonlPath = join(metadataDir, sessionId, "full.jsonl");
    if (!existsSync(jsonlPath)) continue;

    let stat;
    try { stat = statSync(jsonlPath); }
    catch { continue; }

    const liveTag = `live:${Math.floor(stat.mtimeMs)}:${stat.size}`;

    // Skip if we've already indexed this exact (mtime, size) version.
    const existing = await db.shadowSession.findUnique({ where: { sessionId } });
    const seenShas: string[] = existing ? (JSON.parse(existing.seenBlobShas) as string[]) : [];
    if (seenShas.includes(liveTag)) {
      // Per-event author backfill for sessions indexed before we tracked authorship.
      if (existing) {
        const missing = await db.logEvent.count({ where: { shadowSessionId: existing.id, gitUserName: null } });
        if (missing > 0) {
          const rev = findAnyCommitForSessionJsonl(repoPath, sessionId);
          const authorByKey = rev ? getJsonlLineAuthors(repoPath, rev, sessionId) : null;
          if (authorByKey && authorByKey.size > 0) {
            const rows = await db.logEvent.findMany({
              where: { shadowSessionId: existing.id, gitUserName: null },
              select: { id: true, uuid: true, messageId: true },
            });
            let patched = 0;
            for (const r of rows) {
              const key = r.uuid ?? r.messageId;
              const a = key ? authorByKey.get(key) : undefined;
              if (a && (a.name || a.email)) {
                await db.logEvent.update({ where: { id: r.id }, data: { gitUserName: a.name ?? null, gitUserEmail: a.email ?? null } });
                patched++;
              }
            }
            if (patched > 0) process.stderr.write(`live indexer: backfilled author on ${patched} event(s) of ${sessionId.slice(0, 8)} from ${rev!.slice(0, 8)}\n`);
          }
        }
      }
      continue;
    }

    let fullJsonlContent: string;
    try { fullJsonlContent = readFileSync(jsonlPath, "utf8"); }
    catch { continue; }

    const events = parseFullJsonl(fullJsonlContent);
    if (events.length === 0) continue;

    // Extract session metadata from the first event that carries each field.
    const cwdEvent    = events.find((e) => e.cwd);
    const branchEvent = events.find((e) => e.gitBranch);
    const timeEvent   = events.find((e) => e.timestamp);
    const cwd       = cwdEvent?.cwd       ?? null;
    const gitBranch = branchEvent?.gitBranch ?? null;
    const createdAt = timeEvent?.timestamp ? new Date(timeEvent.timestamp) : null;

    // Read the live prompt file if present (live sibling of `prompt.txt`).
    let prompt: string | null = null;
    const promptPath = join(metadataDir, sessionId, "prompt.txt");
    if (existsSync(promptPath)) {
      try { prompt = readFileSync(promptPath, "utf8").trim(); } catch { /* ignore */ }
    }

    // Append the new tag to seenBlobShas so subsequent unchanged scans are no-ops.
    const newSeenShas = JSON.stringify([...seenShas, liveTag]);

    // Find any commit (on any ref) that touched this session's full.jsonl so
    // we can blame per-line authors even after the originating shadow branch
    // has been pruned. Falls back to an empty map if nothing is found.
    const blameRev = findAnyCommitForSessionJsonl(repoPath, sessionId);
    const authorByKey = blameRev ? getJsonlLineAuthors(repoPath, blameRev, sessionId) : new Map<string, { name: string | null; email: string | null }>();

    const shadowSession = await db.shadowSession.upsert({
      where:  { sessionId },
      create: { sessionId, branch: "live", seenBlobShas: newSeenShas, prompt, cwd, gitBranch, createdAt },
      update: { seenBlobShas: newSeenShas, prompt: prompt ?? existing?.prompt ?? null, cwd: cwd ?? existing?.cwd ?? null, gitBranch: gitBranch ?? existing?.gitBranch ?? null, createdAt: createdAt ?? existing?.createdAt ?? null },
    });

    const { events: newEvents } = await indexFullJsonlContent(db, fullJsonlContent, undefined, shadowSession.id, authorByKey);
    process.stderr.write(`live indexer: indexed session ${sessionId.slice(0, 8)} (+${newEvents} events) from disk${authorByKey.size > 0 ? ` (blamed ${authorByKey.size} lines)` : ""}\n`);
    totalSessions++;
  }

  if (totalSessions > 0) {
    await setupLogContentFts(db);
    await syncLogContentFts(db);
  }

  return { sessions: totalSessions };
}

/**
 * Read task checkpoint files from a shadow branch and store parent→child session
 * relationships in the SessionParent table.
 *
 * Task checkpoint files live at:
 *   .entire/metadata/<parentSessionId>/tasks/<toolUseId>/checkpoint.json
 *
 * The child session is identified by finding the LogEvent whose parentToolUseId
 * matches the task's toolUseId (set on the child's first progress event).
 */
async function indexTaskRelationships(
  db: PrismaClient,
  repoPath: string,
  branch: string,
): Promise<void> {
  let output: string;
  try {
    output = gitExec(`ls-tree -r ${branch} -- .entire/metadata/`, repoPath);
  } catch { return; }

  for (const line of output.split("\n")) {
    const m = line.match(
      /^100644 blob ([0-9a-f]+)\s+\.entire\/metadata\/([^/]+)\/tasks\/([^/]+)\/checkpoint\.json$/,
    );
    if (!m) continue;
    const [, blobSha, parentSessionId, toolUseId] = m;

    try {
      const content = readBlobContent(repoPath, blobSha);
      JSON.parse(content); // validate it's parseable; we don't need fields yet

      // Find the child session that references this toolUseId as its parentToolUseId.
      const childEvent = await db.logEvent.findFirst({
        where: {
          parentToolUseId: toolUseId,
          type: "progress",
          sessionId: { not: null },
        },
        select: { sessionId: true },
      });

      const childSessionId = childEvent?.sessionId;
      if (!childSessionId || childSessionId === parentSessionId) continue;

      await db.sessionParent.upsert({
        where:  { childSessionId },
        create: { childSessionId, parentSessionId, toolUseId },
        update: {},
      });
    } catch { /* skip malformed checkpoint */ }
  }
}

import type { PrismaClient } from "../prisma/generated/client/index.js";

// ─── Setup ────────────────────────────────────────────────────────────────────

/**
 * Create the FTS5 virtual table if it doesn't exist.
 * The rowid of LogContentFts equals LogContent.id so results can be joined back.
 * Metadata columns (contentType, logEventId, sessionId, timestamp, toolName) are
 * stored but not indexed (UNINDEXED) — they're used for filtering and display.
 */
export async function setupLogContentFts(db: PrismaClient): Promise<void> {
  await db.$executeRawUnsafe(`
    CREATE VIRTUAL TABLE IF NOT EXISTS LogContentFts USING fts5(
      text,
      thinking,
      toolResultContent,
      toolInput,
      contentType   UNINDEXED,
      logEventId    UNINDEXED,
      sessionId     UNINDEXED,
      timestamp     UNINDEXED,
      toolName      UNINDEXED
    )
  `);
}

// ─── Sync ─────────────────────────────────────────────────────────────────────

/**
 * Insert any LogContent rows not yet present in the FTS index.
 * Safe to call repeatedly — already-indexed rows are skipped via rowid check.
 * Returns the number of rows inserted.
 */
export async function syncLogContentFts(db: PrismaClient): Promise<number> {
  return db.$executeRawUnsafe(`
    INSERT INTO LogContentFts(
      rowid, text, thinking, toolResultContent, toolInput,
      contentType, logEventId, sessionId, timestamp, toolName
    )
    SELECT
      lc.id,
      COALESCE(lc.text,              ''),
      COALESCE(lc.thinking,          ''),
      COALESCE(lc.toolResultContent, ''),
      COALESCE(lc.toolInput,         ''),
      lc.contentType,
      lc.logEventId,
      COALESCE(le.sessionId,  ''),
      COALESCE(le.timestamp,  ''),
      COALESCE(lc.toolName,   '')
    FROM LogContent lc
    LEFT JOIN LogEvent le ON le.id = lc.logEventId
    WHERE lc.id NOT IN (SELECT rowid FROM LogContentFts)
  `);
}

/**
 * Drop and rebuild the FTS index from scratch.
 * Use this after bulk imports when incremental sync is too slow.
 */
export async function rebuildLogContentFts(db: PrismaClient): Promise<void> {
  await db.$executeRawUnsafe(`DELETE FROM LogContentFts`);
  await syncLogContentFts(db);
}

// ─── Search ───────────────────────────────────────────────────────────────────

export interface LogContentSearchResult {
  logContentId: number;
  logEventId: number;
  sessionId: string;
  timestamp: string | null;
  contentType: string;
  toolName: string | null;
  /** "user" | "assistant" — which side of the conversation this content came from. */
  logEventType: string;
  /** FTS5 snippet with «match» markers around matched terms. */
  snippet: string;
  /** BM25 rank (more negative = better match). */
  rank: number;
}

/**
 * Full-text search across LogContent fields (text, thinking, toolResultContent,
 * toolInput).  Accepts standard FTS5 MATCH syntax:
 *   - bare word:   foo
 *   - phrase:      "foo bar"
 *   - prefix:      foo*
 *   - column:      text:foo
 *   - boolean:     foo AND bar, foo OR bar, foo NOT bar
 *
 * Results are ordered by BM25 relevance (best first).
 */
export async function searchLogContent(
  db: PrismaClient,
  query: string,
  limit = 50,
): Promise<LogContentSearchResult[]> {
  type Row = {
    logContentId: number | bigint;
    logEventId: number | bigint;
    sessionId: string;
    timestamp: string | null;
    contentType: string;
    toolName: string | null;
    logEventType: string;
    snippet: string;
    rank: number;
  };

  // Run FTS match in a subquery first, then join for extra metadata.
  const rows = await db.$queryRawUnsafe<Row[]>(`
    SELECT
      fts.logContentId,
      fts.logEventId,
      fts.sessionId,
      fts.timestamp,
      fts.contentType,
      fts.toolName,
      fts.snippet,
      fts.rank,
      le.type   AS logEventType
    FROM (
      SELECT
        rowid                                              AS logContentId,
        logEventId,
        sessionId,
        timestamp,
        contentType,
        toolName,
        snippet(LogContentFts, -1, '«', '»', '…', 24)   AS snippet,
        -- Weight text/thinking 10× higher than toolResultContent/toolInput.
        bm25(LogContentFts, 10, 10, 1, 1)                AS rank
      FROM LogContentFts
      WHERE LogContentFts MATCH ?
      ORDER BY rank
      LIMIT ?
    ) fts
    JOIN LogEvent le ON le.id = fts.logEventId
  `, query, limit);

  return rows.map((r) => ({
    logContentId:  Number(r.logContentId),
    logEventId:    Number(r.logEventId),
    sessionId:     r.sessionId,
    timestamp:     r.timestamp,
    contentType:   r.contentType,
    toolName:      r.toolName || null,
    logEventType:  r.logEventType,
    snippet:       r.snippet,
    rank:          r.rank,
  }));
}

