115	        try {
116	          const body = JSON.parse(Buffer.concat(chunks).toString()) as { v?: number };
117	          resolve(body.v === SERVER_API_VERSION);
118	        } catch {
119	          resolve(false);
120	        }
121	      });
122	    });
123	    req.on("error", () => resolve(false));
124	    req.setTimeout(500, () => { req.destroy(); resolve(false); });
125	  });
126	}
