128	/** Poll until the server responds or we time out (default 30s). */
129	export async function waitForServer(port: number, timeoutMs = 30_000): Promise<void> {
130	  const deadline = Date.now() + timeoutMs;
131	  while (Date.now() < deadline) {
132	    if (await probeServer(port)) return;
133	    await new Promise((r) => setTimeout(r, 500));
134	  }
135	  throw new Error("Gossamer server did not start within 30s");
136	}
