138	const DEFAULT_PORT = 3456;
139	
140	export function getConfiguredPort(): number {
141	  try {
142	    const raw = readFileSync(join(homedir(), ".gossamer", "config.json"), "utf8");
143	    const cfg = JSON.parse(raw) as { port?: number };
144	    return typeof cfg.port === "number" ? cfg.port : DEFAULT_PORT;
145	  } catch {
146	    return DEFAULT_PORT;
147	  }
148	}
