150	function httpGetJson<T>(url: string): Promise<T> {
151	  return new Promise((resolve, reject) => {
152	    const req = httpGet(url, (res) => {
153	      const chunks: Buffer[] = [];
154	      res.on("data", (c: Buffer) => chunks.push(c));
155	      res.on("end", () => {
156	        try { resolve(JSON.parse(Buffer.concat(chunks).toString("utf8")) as T); }
157	        catch (e) { reject(e); }
158	      });
159	    });
160	    req.on("error", reject);
161	    req.setTimeout(5000, () => { req.destroy(); reject(new Error("timeout")); });
162	  });
163	}
164	
165	function httpPostJson<T>(url: string, body: unknown): Promise<T> {
166	  return new Promise((resolve, reject) => {
167	    const data = JSON.stringify(body);
168	    const opts = new URL(url);
169	    const req = httpRequest({
170	      hostname: opts.hostname,
171	      port: opts.port,
172	      path: opts.pathname,
173	      method: "POST",
174	      headers: { "Content-Type": "application/json", "Content-Length": Buffer.byteLength(data) },
175	    }, (res) => {
176	      const chunks: Buffer[] = [];
177	      res.on("data", (c: Buffer) => chunks.push(c));
178	      res.on("end", () => {
179	        try { resolve(JSON.parse(Buffer.concat(chunks).toString("utf8")) as T); }
180	        catch (e) { reject(e); }
181	      });
182	    });
183	    req.on("error", reject);
184	    req.write(data);
185	    req.end();
186	  });
187	}
