207	  static async createOrShow(context: vscode.ExtensionContext, repoPath: string, checkpointProvider: CheckpointTreeProvider) {
208	    if (GossamerPanel.instance) {
209	      GossamerPanel.instance.panel.reveal();
210	      return;
