216	  /** Hide the panel without killing the server (minimizes to nothing; re-open via command). */
217	  static minimize() {
218	    if (!GossamerPanel.instance) return;
219	    // Dispose the webview only — server stays alive
220	    GossamerPanel.instance.disposeWebviewOnly();
