232	  /** Kill and restart the server process, then re-signal the panel when ready. */
233	  static async restart(repoPath: string) {
234	    const port = getConfiguredPort();
235	
236	    // Kill via PID lookup so we hit any process owning the port, not just one
237	    // we happen to have a handle on. This catches servers spawned by another
238	    // window, a previous extension-host activation, or our own untracked spawn.
239	    GossamerPanel.server?.kill();
240	    GossamerPanel.server = undefined;
241	    GossamerPanel.serverPort = undefined;
242	    try {
243	      const pids = execFileSync("lsof", ["-ti", `tcp:${port}`], { encoding: "utf8" })
244	        .trim().split(/\s+/).filter(Boolean);
245	      for (const pid of pids) {
246	        try { process.kill(Number(pid), 9); } catch { /* already gone */ }
247	      }
248	      // Give the OS a moment to free the port.
249	      if (pids.length > 0) await new Promise((r) => setTimeout(r, 300));
250	    } catch { /* lsof found nothing — fine */ }
251	
252	    const instance = GossamerPanel.instance;
253	    if (instance) {
254	      instance.serverReady = false;
255	      instance.panel.webview.postMessage({ type: "server_starting" });
256	      try {
257	        await instance.spawnServer();
258	        await waitForServer(port);
259	        await instance.ensureRepoRegistered();
260	        instance.serverReady = true;
261	        instance.panel.webview.postMessage({ type: "server_ready" });
262	        instance.checkpointProvider.setBranchFromWorkspace(instance.repoPath, instance.port).catch(console.error);
263	      } catch (err) {
264	        instance.reportServerError(String(err));
265	      }
266	    } else {
267	      // No panel — spawn a detached server anyway so the sidebar still works.
268	      const nodeExec = getSystemNode();
269	      if (existsSync(SERVE_SCRIPT)) {
270	        const proc = spawn(nodeExec, [SERVE_SCRIPT, "--repo-dir", repoPath, "--port", String(port)], {
271	          stdio: ["ignore", "pipe", "pipe"],
272	          env: { ...process.env, FORCE_COLOR: "0" },
273	        });
274	        proc.on("exit", () => { if (GossamerPanel.server === proc) { GossamerPanel.server = undefined; GossamerPanel.serverPort = undefined; } });
275	        GossamerPanel.server = proc;
276	        GossamerPanel.serverPort = port;
277	      }
278	    }
279	  }
