291	  private constructor(context: vscode.ExtensionContext, repoPath: string, port: number, checkpointProvider: CheckpointTreeProvider) {
292	    this.context            = context;
293	    this.repoPath           = repoPath;
294	    this.port               = port;
295	    this.checkpointProvider = checkpointProvider;
296	
297	    this.panel = vscode.window.createWebviewPanel(
298	      "gossamer",
299	      "Gossamer",
300	      vscode.ViewColumn.Two,
301	      {
302	        enableScripts: true,
303	        enableFindWidget: true,
304	        retainContextWhenHidden: true,
305	        localResourceRoots: [
306	          vscode.Uri.joinPath(context.extensionUri, "dist", "webview"),
307	        ],
308	      },
309	    );
310	
311	    this.panel.webview.html = this.getWebviewHtml(context);
312	    this.panel.onDidDispose(() => this.cleanup(false), undefined, this.disposables);
313	    this.panel.webview.onDidReceiveMessage(
314	      (msg: { type: string; sessionId?: string; title?: string; checkpointId?: string; filePath?: string }) => {
315	        if (msg.type === "open_session" && msg.sessionId) {
316	          SessionDetailPanel.createOrShow(this.context, msg.sessionId, msg.title ?? msg.sessionId.slice(0, 8), this.port, this.checkpointProvider, this.repoPath);
317	        }
318	        if (msg.type === "show_checkpoint_diff" && msg.checkpointId && msg.filePath) {
319	          openCheckpointDiff(this.port, msg.checkpointId, msg.filePath).catch(console.error);
320	        }
321	        if (msg.type === "new_session") {
322	          this.promptAndSpawnSession().catch(console.error);
323	        }
324	        if (msg.type === "search_sessions") {
325	          this.openSearchQuickPick().catch(console.error);
326	        }
327	        if (msg.type === "minimize") {
328	          GossamerPanel.minimize();
329	        }
330	        if (msg.type === "restart_server") {
331	          GossamerPanel.restart(this.repoPath);
332	        }
333	        if (msg.type === "open_log_file") {
334	          vscode.workspace.openTextDocument(vscode.Uri.file(LOG_PATH))
335	            .then((doc) => vscode.window.showTextDocument(doc, { preview: false }))
336	            .then(undefined, (err) => vscode.window.showErrorMessage(`Failed to open log: ${err}`));
337	        }
338	      },
339	      undefined,
340	      this.disposables,
341	    );
342	    this.watchGitBranch();
343	
344	    // Signal the webview once the server is accepting requests.
345	    // Also re-signal on visibility changes (e.g. tab moved to a new window causes a reload).
346	    this.panel.onDidChangeViewState(
347	      (e) => { if (e.webviewPanel.visible && this.serverReady) this.panel.webview.postMessage({ type: "server_ready" }); },
348	      undefined,
349	      this.disposables,
350	    );
351	    // spawnServer must finish before waitForServer starts — it may kill an outdated
352	    // server and we must not let waitForServer resolve on that dead server.
353	    this.spawnServer()
354	      .then(() => waitForServer(this.port))
355	      .then(() => this.ensureRepoRegistered())
356	      .then(() => {
357	        this.serverReady = true;
358	        this.panel.webview.postMessage({ type: "server_ready" });
359	        this.checkpointProvider.setBranchFromWorkspace(this.repoPath, this.port).catch(console.error);
360	        this.watchBranchForCheckpointReload();
361	      })
362	      .catch((err) => this.reportServerError(String(err)));
363	  }
