365	  /**
366	   * Reload the checkpoint tree when the branch changes (.git/HEAD rewrites)
367	   * or new commits land on the current branch (.git/refs/heads/<branch>).
368	   * The ref file is small, rewritten atomically by git on commit, and poll-free.
369	   */
370	  private watchBranchForCheckpointReload(): void {
371	    const headPath = join(this.repoPath, ".git", "HEAD");
372	    const reload = () => this.checkpointProvider.setBranchFromWorkspace(this.repoPath, this.port).catch(() => undefined);
373	    try {
374	      const headWatcher = watch(headPath, { persistent: false }, reload);
375	      this.disposables.push({ dispose: () => headWatcher.close() });
376	    } catch { /* HEAD missing — non-fatal */ }
377	    try {
378	      const refsDir = join(this.repoPath, ".git", "refs", "heads");
379	      const refsWatcher = watch(refsDir, { persistent: false, recursive: true }, reload);
380	      this.disposables.push({ dispose: () => refsWatcher.close() });
381	    } catch { /* refs/heads missing — non-fatal */ }
382	  }
