384	  /** Refresh the checkpoint tree on demand. */
385	  static refreshCheckpointTree(): void {
386	    const inst = GossamerPanel.instance;
387	    if (!inst || !inst.serverReady) return;
388	    inst.checkpointProvider.setBranchFromWorkspace(inst.repoPath, inst.port).catch(console.error);
389	  }
