391	  private async spawnServer() {
392	    // Reuse existing static server if already running on the same port
393	    if (GossamerPanel.server && GossamerPanel.serverPort === this.port) {
394	      console.log("[Gossamer] reusing existing server on port", this.port);
395	      return;
396	    }
397	
398	    // Check whether a server is already on the port.
399	    // - Compatible version → reuse it (safe for two VS Code windows sharing one server).
400	    // - Outdated version   → SIGKILL it and give the OS 300 ms to release the port.
401	    // - Nothing there      → fall through to spawn.
402	    if (await probeServerVersion(this.port)) {
403	      console.log("[Gossamer] reusing compatible server on port", this.port);
404	      GossamerPanel.serverPort = this.port;
405	      return;
406	    }
407	    if (await probeServer(this.port)) {
408	      console.log("[Gossamer] killing outdated server on port", this.port);
409	      try {
410	        execFileSync("lsof", ["-ti", `tcp:${this.port}`], { encoding: "utf8" })
411	          .trim().split(/\s+/)
412	          .filter(Boolean)
413	          // SIGKILL (9): bypasses signal handlers, OS releases port immediately.
414	          .forEach((pid) => { try { process.kill(Number(pid), 9); } catch {} });
415	      } catch { /* lsof may find nothing — proceed */ }
416	      await new Promise((r) => setTimeout(r, 300));
417	    }
418	
419	    if (!existsSync(SERVE_SCRIPT)) {
420	      const msg = `Gossamer server script not found at ${SERVE_SCRIPT}. Run \`npm run build\` in the gossamer repo root first.`;
421	      console.error("[Gossamer]", msg);
422	      appendStderr(msg + "\n");
423	      return;
424	    }
425	
426	    const nodeExec = getSystemNode();
427	    console.log(`[Gossamer] spawning: ${nodeExec} ${SERVE_SCRIPT} --repo-dir ${this.repoPath} --port ${this.port}`);
428	
429	    // Reset state for the new launch
430	    stderrBuffer = "";
431	    GossamerPanel.lastExit = undefined;
432	    const log = getLogStream();
433	    log?.write(`--- spawn ${new Date().toISOString()} pid=? repo=${this.repoPath} port=${this.port} ---\n`);
434	
435	    const proc = spawn(nodeExec, [SERVE_SCRIPT, "--repo-dir", this.repoPath, "--port", String(this.port)], {
436	      stdio: ["ignore", "pipe", "pipe"],
437	      env: { ...process.env, FORCE_COLOR: "0" },
438	    });
439	
440	    proc.stdout?.on("data", (d: Buffer) => {
441	      const text = d.toString();
442	      console.log("[Gossamer server stdout]", text.trim());
443	      log?.write(text);
444	    });
445	    proc.stderr?.on("data", (d: Buffer) => {
446	      const text = d.toString();
447	      console.error("[Gossamer server stderr]", text.trim());
448	      appendStderr(text);
449	      log?.write(text);
450	    });
451	    proc.on("error", (err) => {
452	      console.error("[Gossamer] failed to spawn server:", err.message);
453	      appendStderr(`spawn error: ${err.message}\n`);
454	      GossamerPanel.instance?.reportServerError(`failed to start server — ${err.message}`);
455	    });
456	    proc.on("exit", (code, signal) => {
457	      console.log(`[Gossamer server] exited code=${code} signal=${signal}`);
458	      log?.write(`--- exit code=${code} signal=${signal} at ${new Date().toISOString()} ---\n`);
459	      GossamerPanel.lastExit = { code, signal };
460	      if (GossamerPanel.server === proc) {
461	        GossamerPanel.server = undefined;
462	        GossamerPanel.serverPort = undefined;
463	        const instance = GossamerPanel.instance;
464	        if (instance && !instance.serverReady) {
465	          instance.reportServerError(`server exited before becoming ready (code=${code}, signal=${signal})`);
466	        }
467	      }
468	    });
469	
470	    GossamerPanel.server = proc;
471	    GossamerPanel.serverPort = this.port;
472	  }
