486	  private async openSearchQuickPick(): Promise<void> {
487	    interface SessionData {
488	      sessionId: string;
489	      intent: string | null;
490	      prompt: string | null;
491	      repoName: string | null;
492	      cwd: string;
493	      slug?: string | null;
494	      customTitle?: string | null;
495	    }
496	    interface ContentResult {
497	      sessionId: string;
498	      snippet: string;
499	      contentType: string;
500	    }
501	    type QP = vscode.QuickPickItem & { sessionId: string; sessionTitle: string };
502	
503	    const allSessions = await httpGetJson<SessionData[]>(`http://localhost:${this.port}/api/sessions`);
504	
505	    const sessionLabel = (s: SessionData) =>
506	      s.intent ?? s.prompt?.slice(0, 80) ?? s.customTitle ?? s.slug ?? s.sessionId.slice(0, 8) ?? "";
507	
508	    const toSessionItem = (s: SessionData): QP => ({
509	      sessionId:    s.sessionId,
510	      sessionTitle: sessionLabel(s),
511	      label:        sessionLabel(s),
512	      description:  s.repoName ?? s.cwd.split("/").pop() ?? "",
513	      detail:       s.cwd,
514	    });
515	
516	    const buildItems = (query: string, contentResults: ContentResult[]): QP[] => {
517	      const q = query.toLowerCase();
518	      const sessionMatches = query
519	        ? allSessions.filter((s) =>
520	            sessionLabel(s).toLowerCase().includes(q) ||
521	            (s.repoName ?? "").toLowerCase().includes(q) ||
522	            s.cwd.toLowerCase().includes(q),
523	          )
524	        : allSessions;
525	
526	      const items: QP[] = [];
527	
528	      if (sessionMatches.length > 0) {
529	        if (contentResults.length > 0) {
530	          items.push({ kind: vscode.QuickPickItemKind.Separator, label: "Sessions", sessionId: "", sessionTitle: "" });
531	        }
532	        items.push(...sessionMatches.map(toSessionItem));
533	      }
534	
535	      if (contentResults.length > 0) {
536	        const seenInSessions = new Set(sessionMatches.map((s) => s.sessionId));
537	        items.push({ kind: vscode.QuickPickItemKind.Separator, label: "Chat History", sessionId: "", sessionTitle: "" });
538	        for (const r of contentResults) {
539	          const session = allSessions.find((s) => s.sessionId === r.sessionId);
540	          const sLabel  = sessionLabel(session ?? { sessionId: r.sessionId, intent: null, prompt: null, repoName: null, cwd: "", slug: null });
541	          const snippet = r.snippet.replace(/«/g, "").replace(/»/g, "").trim();
542	          items.push({
543	            sessionId:    r.sessionId,
544	            sessionTitle: sLabel,
545	            label:        snippet || sLabel,
546	            description:  sLabel,
547	            detail:       session?.cwd ?? "",
548	            alwaysShow:   true,
549	          });
550	        }
551	      }
552	
553	      return items;
554	    };
555	
556	    const qp = vscode.window.createQuickPick<QP>();
557	    qp.placeholder = "Search sessions and chat history…";
558	    qp.matchOnDescription = false;
559	    qp.matchOnDetail = false;
560	    qp.items = allSessions.map(toSessionItem);
561	
562	    let debounce: ReturnType<typeof setTimeout> | undefined;
563	
564	    qp.onDidChangeValue((query) => {
565	      if (debounce) clearTimeout(debounce);
566	      if (!query.trim()) {
567	        qp.busy = false;
568	        qp.items = allSessions.map(toSessionItem);
569	        return;
570	      }
571	      qp.busy = true;
572	      debounce = setTimeout(async () => {
573	        let contentResults: ContentResult[] = [];
574	        try {
575	          contentResults = await httpGetJson<ContentResult[]>(
576	            `http://localhost:${this.port}/api/search?q=${encodeURIComponent(query)}&limit=20`,
577	          );
578	        } catch { /* FTS syntax error — show session matches only */ }
579	        qp.items = buildItems(query, contentResults);
580	        qp.busy = false;
581	      }, 300);
582	    });
583	
584	    qp.onDidAccept(() => {
585	      const selected = qp.selectedItems[0];
586	      const query = qp.value.trim();
587	      qp.dispose();
588	      if (selected?.sessionId) {
589	        SessionDetailPanel.createOrShow(
590	          this.context,
591	          selected.sessionId,
592	          selected.sessionTitle,
593	          this.port,
594	          this.checkpointProvider,
595	          this.repoPath,
596	          query || undefined,
597	        );
598	      }
599	    });
600	
601	    qp.onDidHide(() => {
602	      if (debounce) clearTimeout(debounce);
603	      qp.dispose();
604	    });
605	    qp.show();
606	  }
