608	  private async promptAndSpawnSession(): Promise<void> {
609	    // Pick agent — offer choices based on which agents have been used in this repo
610	    interface SessionStub { agent: string | null }
611	    let agentCli = DEFAULT_AGENT_CLI;
612	    try {
613	      const sessions = await httpGetJson<SessionStub[]>(`http://localhost:${this.port}/api/sessions`);
614	      const usedAgents = [...new Set(sessions.map((s) => s.agent).filter(Boolean) as string[])];
615	      const knownAgents = usedAgents.filter((a) => AGENT_CLI[a]);
616	      if (knownAgents.length > 1) {
617	        const picked = await vscode.window.showQuickPick(
618	          knownAgents.map((a) => ({ label: a, description: AGENT_CLI[a].bin })),
619	          { title: "Choose agent", ignoreFocusOut: true },
620	        );
621	        if (!picked) return;
622	        agentCli = AGENT_CLI[picked.label];
623	      } else if (knownAgents.length === 1) {
624	        agentCli = AGENT_CLI[knownAgents[0]];
625	      }
626	    } catch { /* use default */ }
627	
628	    const prompt = await vscode.window.showInputBox({
629	      title: `New ${agentCli.bin} Session`,
630	      prompt: `What do you want ${agentCli.bin} to do?`,
631	      placeHolder: "Describe the task…",
632	      ignoreFocusOut: true,
633	    });
634	    if (!prompt) return;
635	
636	    const name = await vscode.window.showInputBox({
637	      title: "Session Name (optional)",
638	      prompt: "Give this session a name, or press Enter to skip",
639	      placeHolder: "e.g. refactor auth module",
640	      ignoreFocusOut: true,
641	    });
642	
643	    const escaped = prompt.replace(/"/g, '\\"');
644	    const terminal = vscode.window.createTerminal({
645	      name: name || agentCli.bin,
646	      cwd: this.repoPath,
647	    });
648	    terminal.show();
649	    terminal.sendText(`${agentCli.bin} "${escaped}"`, true);
650	    if (name && agentCli.renameCmd) {
651	      setTimeout(() => terminal.sendText(`${agentCli.renameCmd} ${name}`, true), 2000);
652	    }
653	  }
