655	  private async ensureRepoRegistered(): Promise<void> {
656	    const current = await httpGetJson<unknown>(`http://localhost:${this.port}/api/repos/current?localPath=${encodeURIComponent(this.repoPath)}`);
657	    if (current !== null) return; // already registered
658	
659	    const name = basename(this.repoPath);
660	    let remote = "";
661	    try {
662	      const { stdout } = await execFileAsync("git", ["-C", this.repoPath, "remote", "get-url", "origin"]);
663	      remote = stdout.trim();
664	    } catch { /* no remote configured */ }
665	
666	    const checkpointRemote = readCheckpointRemote(this.repoPath, remote);
667	
668	    console.log(`[Gossamer] registering repo: ${name} at ${this.repoPath}`);
669	    await httpPostJson(`http://localhost:${this.port}/api/repos`, {
670	      name,
671	      localPath: this.repoPath,
672	      remote,
673	      ...(checkpointRemote ? { checkpointRemote } : {}),
674	    });
675	  }
676	
677	  private watchGitBranch() {
678	    const gitDir = join(this.repoPath, ".git");
679	    try {
680	      this.watcher = watch(gitDir, { recursive: false }, (_event, filename) => {
681	        // The server polls shadows every 5s already; this is just a hint for future use
682	        if (filename === "packed-refs" || (filename ?? "").startsWith("refs/")) {
683	          // Server handles re-indexing internally
684	        }
685	      });
686	    } catch { /* git dir unavailable */ }
687	  }
688	
689	  private getWebviewHtml(context: vscode.ExtensionContext): string {
690	    const webview   = this.panel.webview;
691	    const distUri   = vscode.Uri.joinPath(context.extensionUri, "dist", "webview");
692	    const scriptUri = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.js"));
693	    const styleUri  = webview.asWebviewUri(vscode.Uri.joinPath(distUri, "assets", "index.css"));
694	    const nonce     = getNonce();
