709	  <script nonce="${nonce}">window.__GOSSAMER_PORT__ = ${port}; window.__GOSSAMER_REPO_PATH__ = ${JSON.stringify(this.repoPath)};</script>
710	  <script nonce="${nonce}" type="module" src="${scriptUri}"></script>
711	</body>
712	</html>`;
