/** Probe the server once; resolves true if it responds, false otherwise. */
function probeServer(port: number): Promise<boolean> {
  return new Promise((resolve) => {
    const req = httpGet(`http://localhost:${port}/health`, (res: any) => {
      res.destroy();
      resolve(true);
    });
    req.on("error", () => resolve(false));
    // Each probe runs against localhost — failures are immediate (ECONNREFUSED).
    // The timeout only matters if the OS is being slow accepting connections,
    // so 200ms is plenty.
    req.setTimeout(200, () => { req.destroy(); resolve(false); });
  });
}

