21	  event: string;
22	  sessionId: string;
23	  blocked: boolean;
24	  data: unknown;
25	  summary: string | null;
26	  keywords: string[];
27	  gitUserName?: string | null;
28	  gitUserEmail?: string | null;
29	  _sourceLogEventId?: number;
30	  _extraSourceLogEventIds?: number[];
31	  _sourceUuid?: string;
32	}
33	
34	export type DisplayItem =
35	  | { kind: "event"; event: Event }
36	  | { kind: "toolGroup"; tools: ToolUseData[] };
37	
38	export type RenderItem =
39	  | { kind: "event"; event: Event }
40	  | { kind: "claudeTurn"; toolGroups: ToolUseData[][]; stop: Event | null };
41	
42	// ── logEventsToEvents ─────────────────────────────────────────────────────────
43	
44	function str(v: unknown): string { return typeof v === "string" ? v : ""; }
45	
46	export function logEventsToEvents(logEvents: LogEventItem[]): Event[] {
47	  const result: Event[] = [];
48	  let id = -1;
49	  let lastAssistantText: string | null = null;
50	  let lastAssistantThinking: string | null = null;
51	  let lastAssistantLogEventId: number | null = null;
52	  let lastThinkingLogEventId: number | null = null;
53	  let lastThinkingUuid: string | null = null;
54	  let lastToolsLogEventId: number | null = null;
55	  let lastToolsUuid: string | null = null;
56	  let hasRedactedThinking = false;
57	  const currentTurnLogEventIds: number[] = [];
58	
59	  const filtered = logEvents.filter(
60	    (e) => !e.isSidechain && e.type !== "file-history-snapshot" && e.type !== "progress",
61	  );
62	
63	  const first = filtered[0];
64	  if (first) {
65	    result.push({ id: id--, timestamp: first.timestamp ?? "", event: "SessionStart", sessionId: first.sessionId ?? "", blocked: false, data: { cwd: first.cwd ?? "" }, summary: null, keywords: [], _sourceLogEventId: first.id });
66	  }
67	
68	  for (const le of filtered) {
69	    const ts  = le.timestamp ?? "";
70	    const sid = le.sessionId ?? "";
71	
72	    if (le.type === "user") {
73	      const toolResults = le.contents.filter((c) => c.contentType === "tool_result");
74	      const textBlocks  = le.contents.filter((c) => c.contentType === "text");
75	      const imageBlocks = le.contents.filter((c) => c.contentType === "image");
76	
77	      if (toolResults.length > 0) {
78	        for (const tr of toolResults) {
79	          const failed = tr.isError === true;
80	          result.push({ id: id--, timestamp: ts, event: failed ? "PostToolUseFailure" : "PostToolUse", sessionId: sid, blocked: false, data: { tool_use_id: tr.toolUseId, tool_response: !failed ? (tr.toolResultContent ?? "") : undefined, error: failed ? (tr.toolResultContent ?? "") : undefined }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
81	        }
82	      } else if (textBlocks.length > 0 || imageBlocks.length > 0) {
83	        const prompt  = textBlocks.map((b) => b.text ?? "").join("\n\n");
84	        const images  = imageBlocks.map((b) => ({ data: b.imageData, mediaType: b.imageMediaType })).filter((b) => b.data);
85	        result.push({ id: id--, timestamp: ts, event: "UserPromptSubmit", sessionId: sid, blocked: false, data: { prompt, images }, summary: null, keywords: [], gitUserName: le.gitUserName, gitUserEmail: le.gitUserEmail, _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
86	      }
87	
88	    } else if (le.type === "assistant") {
89	      const toolUses            = le.contents.filter((c) => c.contentType === "tool_use");
90	      const textBlocks          = le.contents.filter((c) => c.contentType === "text");
91	      const thinkingBlocks      = le.contents.filter((c) => c.contentType === "thinking");
92	      const redactedThinkingBlocks = le.contents.filter((c) => c.contentType === "redacted_thinking");
93	
94	      if (!currentTurnLogEventIds.includes(le.id)) currentTurnLogEventIds.push(le.id);
95	
96	      if (textBlocks.length > 0) {
97	        const newText = textBlocks.map((b) => b.text ?? "").filter(Boolean).join("\n\n");
98	        if (lastAssistantText !== null && lastToolsLogEventId !== null) {
99	          lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + lastAssistantText : lastAssistantText;
100	        }
101	        lastAssistantText = newText;
102	        lastAssistantLogEventId = le.id;
103	      }
104	      if (thinkingBlocks.length > 0) {
105	        const thinking = thinkingBlocks.map((b) => b.thinking ?? "").filter(Boolean).join("\n\n");
106	        lastAssistantThinking = lastAssistantThinking ? lastAssistantThinking + "\n\n" + thinking : thinking;
107	        lastThinkingLogEventId = le.id;
108	        lastThinkingUuid = le.uuid ?? null;
109	        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
110	      }
111	      if (redactedThinkingBlocks.length > 0) {
112	        hasRedactedThinking = true;
113	        if (lastAssistantLogEventId === null) lastAssistantLogEventId = le.id;
114	      }
115	      for (const tu of toolUses) {
116	        lastToolsLogEventId = le.id;
117	        lastToolsUuid = le.uuid ?? null;
118	        result.push({ id: id--, timestamp: ts, event: "PreToolUse", sessionId: sid, blocked: false, data: { tool_name: tu.toolName ?? "?", tool_use_id: tu.toolUseId, tool_input: tu.toolInput }, summary: null, keywords: [], _sourceLogEventId: le.id, _sourceUuid: le.uuid ?? undefined });
119	      }
