export async function fetchLogEvents(id: string, sinceId?: number): Promise<LogEventItem[]> {
  const params = new URLSearchParams();
  if (repoPath()) params.set("localPath", repoPath());
  if (sinceId && sinceId > 0) params.set("sinceId", String(sinceId));
  const qs = params.toString() ? `?${params}` : "";
  const res = await fetch(`${API_BASE()}/v2/sessions/${encodeURIComponent(id)}/log-events${qs}`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  return res.json() as Promise<LogEventItem[]>;
}

export interface UpdateScope {
  /** repo localPath the change came from. Absent → unscoped (e.g. manual sync). */
  localPath?: string;
}

export function subscribeToUpdates(onUpdate: (scope: UpdateScope) => void): () => void {
  let ws: WebSocket | null = null;
  let timer: ReturnType<typeof setTimeout> | null = null;
  let closed = false;
  let delay  = 1000;

  function connect() {
    if (closed) return;
    ws = new WebSocket(WS_URL());
    ws.onopen  = () => { delay = 1000; };
    ws.onmessage = (e) => {
      try {
        const msg = JSON.parse(e.data as string) as { type: string; localPath?: string };
        if (msg.type === "sessions_updated") onUpdate({ localPath: msg.localPath });
      } catch { /* ignore */ }
    };
    ws.onclose = () => {
      if (closed) return;
      timer = setTimeout(() => { delay = Math.min(delay * 2, 30000); connect(); }, delay);
    };
    ws.onerror = () => ws?.close();
  }

  connect();
  return () => {
    closed = true;
    if (timer !== null) clearTimeout(timer);
    ws?.close();
  };
}

