export function SessionDetail({ sessionId, title, onBack }: Props) {
  const [session, setSession]         = useState<Session | null>(null);
  const [renderItems, setRenderItems] = useState<RenderItem[]>([]);
  const [loading, setLoading]         = useState(true);
  const [error, setError]             = useState<string | null>(null);
  const viewport = useRef<HTMLDivElement>(null);
  const initialLoadDone = useRef(false);
  // Refs hold the rolling raw log events + watermark so WS-driven delta fetches
  // can append onto the existing array without redownloading everything.
  const logEventsRef = useRef<LogEventItem[]>([]);
  const maxLogEventIdRef = useRef<number>(0);
  // Latest session metadata — kept in a ref so the WS callback can compare its
  // repoRoot against incoming broadcast scopes without retriggering subscribe.
  const sessionRef = useRef<Session | null>(null);
  const matchTerms = HIGHLIGHT_TERMS;
  const agentLabel = session?.agent ?? "Claude";
  // If any event carries its own author (e.g. a forked session mixing authors),
  // don't fall back to the session-level user — that would misattribute events
  // whose author we don't know to whoever forked/owns the session.
  const hasPerEventAuthor = renderItems.some(
    (r) => r.kind === "event" && !!r.event.gitUserName,
  );
  const userInfo =
    !hasPerEventAuthor && session?.gitUserName ? { name: session.gitUserName } : undefined;

  function rebuildRenderItems(allLogEvents: LogEventItem[]): void {
    const events  = logEventsToEvents(allLogEvents);
    const display = groupEvents(events);
    setRenderItems(groupClaudeTurns(display));
  }

  async function loadInitial() {
    try {
      const [sess, logEvents] = await Promise.all([
        fetchSession(sessionId),
        fetchLogEvents(sessionId),
      ]);
      setSession(sess);
      sessionRef.current = sess;
      logEventsRef.current = logEvents;
      maxLogEventIdRef.current = logEvents.reduce((m, e) => (e.id > m ? e.id : m), 0);
      rebuildRenderItems(logEvents);
      setError(null);
    } catch (err) {
      setError(String(err));
    }
  }

  async function applyDelta() {
    try {
      const newEvents = await fetchLogEvents(sessionId, maxLogEventIdRef.current);
      if (newEvents.length === 0) return;
      logEventsRef.current = [...logEventsRef.current, ...newEvents];
      maxLogEventIdRef.current = newEvents.reduce(
        (m, e) => (e.id > m ? e.id : m),
        maxLogEventIdRef.current,
      );
      rebuildRenderItems(logEventsRef.current);
      // New events implies session metadata could have changed too (slug,
      // updatedAt, intent). Refetch it once to keep the header in sync — we
      // skip this when no events arrived, so quiet broadcasts are free.
      try {
        const sess = await fetchSession(sessionId);
        setSession(sess);
        sessionRef.current = sess;
      } catch { /* tolerated */ }
    } catch { /* tolerated */ }
  }

  const didInitialScroll = useRef(false);

  useEffect(() => {
    initialLoadDone.current = false;
    didInitialScroll.current = false;
    logEventsRef.current = [];
    maxLogEventIdRef.current = 0;
    loadInitial().finally(() => {
      setLoading(false);
      initialLoadDone.current = true;
    });
  }, [sessionId]);

  // Scroll after the initial render completes (loading → false flushes the content to DOM)
  useEffect(() => {
    if (loading || didInitialScroll.current) return;
    didInitialScroll.current = true;
    if (matchTerms.length > 0) {
      const mark = viewport.current?.querySelector("mark");
      mark?.scrollIntoView({ behavior: "smooth", block: "center" });
    } else {
      const el = viewport.current;
      if (el) el.scrollTop = el.scrollHeight;
    }
  }, [loading]);

  useEffect(() => {
    return subscribeToUpdates((scope) => {
      // If the broadcast is scoped to a different repo than ours, skip work
      // entirely — multi-repo users no longer pay for activity in unrelated
      // repos. Unscoped broadcasts (manual sync, etc.) still fall through.
      const ourRepo = sessionRef.current?.repoRoot ?? null;
      if (scope.localPath && ourRepo && scope.localPath !== ourRepo) return;
      if (!initialLoadDone.current) return;
      void applyDelta();
    });
  }, [sessionId]);

