  // Scroll after the initial render completes (loading → false flushes the content to DOM)
  useEffect(() => {
    if (loading || didInitialScroll.current) return;
    didInitialScroll.current = true;
    if (matchTerms.length > 0) {
      const mark = viewport.current?.querySelector("mark");
      mark?.scrollIntoView({ behavior: "smooth", block: "center" });
    } else {
      const el = viewport.current;
      if (el) el.scrollTop = el.scrollHeight;
    }
  }, [loading]);

  useEffect(() => {
    return subscribeToUpdates((scope) => {
      // If the broadcast is scoped to a different repo than ours, skip work
      // entirely — multi-repo users no longer pay for activity in unrelated
      // repos. Unscoped broadcasts (manual sync, etc.) still fall through.
      const ourRepo = sessionRef.current?.repoRoot ?? null;
      if (scope.localPath && ourRepo && scope.localPath !== ourRepo) return;
      if (!initialLoadDone.current) return;
      void applyDelta();
    });
  }, [sessionId]);

